"use strict";(self.webpackChunkhosting_capacity_service=self.webpackChunkhosting_capacity_service||[]).push([["251"],{9311:function(e,t,o){o.r(t),o.d(t,{metadata:()=>n,default:()=>h,frontMatter:()=>i,contentTitle:()=>r,toc:()=>d,assets:()=>l});var n=JSON.parse('{"id":"reference/closed-loop-voltage-control","title":"Closed Loop Voltage Control","description":"Closed Loop Voltage Control (CLVC) is the algorithm used to model how zone substations regulate voltage in response to load and generation changes. The CLVC settings affect voltage levels across the network and therefore influence both overvoltage constraint results (generation-driven) and undervoltage constraint results (load-driven).","source":"@site/docs/reference/CLVC.mdx","sourceDirName":"reference","slug":"/reference/closed-loop-voltage-control","permalink":"/evolve/docs/hosting-capacity-service/next/reference/closed-loop-voltage-control","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"id":"closed-loop-voltage-control","title":"Closed Loop Voltage Control","slug":"/reference/closed-loop-voltage-control","toc_max_heading_level":3},"sidebar":"theSidebar","previous":{"title":"Node Level Results","permalink":"/evolve/docs/hosting-capacity-service/next/reference/node-level-results"}}'),a=o(4848),s=o(8453);let i={id:"closed-loop-voltage-control",title:"Closed Loop Voltage Control",slug:"/reference/closed-loop-voltage-control",toc_max_heading_level:3},r="Closed Loop Voltage Control (CLVC)",l={},d=[{value:"How It Works",id:"how-it-works",level:2},{value:"Configuration Parameters",id:"configuration-parameters",level:2},{value:"Voltage Setpoint (<code>closed_loop_v_reg_set_point</code>)",id:"voltage-setpoint-closed_loop_v_reg_set_point",level:3},{value:"Voltage Deadband (<code>closed_loop_v_band</code>)",id:"voltage-deadband-closed_loop_v_band",level:3},{value:"Time Delay (<code>closed_loop_time_delay</code>)",id:"time-delay-closed_loop_time_delay",level:3},{value:"Voltage Limit (<code>closed_loop_v_limit</code>)",id:"voltage-limit-closed_loop_v_limit",level:3},{value:"Deployment Flags",id:"deployment-flags",level:3},{value:"Scope and Limitations",id:"scope-and-limitations",level:2},{value:"Comparison with Other Voltage Control Options",id:"comparison-with-other-voltage-control-options",level:2},{value:"Choosing Settings",id:"choosing-settings",level:2},{value:"Example Configurations",id:"example-configurations",level:3}];function c(e){let t={admonition:"admonition",code:"code",h1:"h1",h2:"h2",h3:"h3",header:"header",hr:"hr",p:"p",pre:"pre",strong:"strong",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"closed-loop-voltage-control-clvc",children:"Closed Loop Voltage Control (CLVC)"})}),"\n",(0,a.jsx)(t.p,{children:"Closed Loop Voltage Control (CLVC) is the algorithm used to model how zone substations regulate voltage in response to load and generation changes. The CLVC settings affect voltage levels across the network and therefore influence both overvoltage constraint results (generation-driven) and undervoltage constraint results (load-driven)."}),"\n",(0,a.jsx)(t.h2,{id:"how-it-works",children:"How It Works"}),"\n",(0,a.jsx)(t.p,{children:"Zone substation transformers have discrete tap positions that adjust the output voltage in small increments. CLVC uses measurements at a sensing point to determine whether a tap change is needed. The sensing point is the MV-side node of the furthest three-phase distribution transformer from the zone substation, measured by cumulative upstream MV line length (resetting at any intermediate voltage regulators). On three-phase feeders, phase B is specifically monitored at this node."}),"\n",(0,a.jsx)(t.p,{children:"Because the sensing point is on the MV network, CLVC is regulating voltage at the far end of the MV feeder - LV customer voltages are affected indirectly through the distribution transformer ratios downstream."}),"\n",(0,a.jsx)(t.p,{children:"The algorithm continuously compares the sensed voltage against a target setpoint expressed in per-unit (p.u.), where 1.0 p.u. equals nominal voltage. If the voltage drifts outside a configured tolerance band (the deadband) and remains there for longer than the configured time delay, the algorithm commands a tap change to bring voltage back within range. A hard voltage ceiling prevents voltage from exceeding a defined limit regardless of other settings."}),"\n",(0,a.jsx)(t.admonition,{type:"note",children:(0,a.jsx)(t.p,{children:"The p.u. setpoint, voltage limit, and deadband percentage are all converted to absolute volt values internally, using the nominal voltage at the sensing bus as defined in the CIM network model. If nominal voltage data is missing or incorrect for that location in the network model, CLVC behaviour may be unexpected. This is worth checking if a feeder with CLVC enabled is producing unusual voltage results."})}),"\n",(0,a.jsx)(t.h2,{id:"configuration-parameters",children:"Configuration Parameters"}),"\n",(0,a.jsxs)(t.h3,{id:"voltage-setpoint-closed_loop_v_reg_set_point",children:["Voltage Setpoint (",(0,a.jsx)(t.code,{children:"closed_loop_v_reg_set_point"}),")"]}),"\n",(0,a.jsx)(t.p,{children:"The setpoint is the target voltage at the sensing point, expressed in per-unit (1.0 p.u. = nominal voltage at that location). Most utilities operate below 1.0 p.u. to provide headroom for voltage rise caused by distributed generation, particularly solar PV. The gap between the setpoint and the voltage limit defines the effective overvoltage headroom window."}),"\n",(0,a.jsx)(t.p,{children:"However, the setpoint also affects the other direction: on long feeders under heavy load, voltage naturally drops toward the far end, and a lower setpoint means the regulator is less aggressive in compensating for that drop. A setpoint that improves overvoltage headroom for DER may therefore worsen undervoltage outcomes under high load, and vice versa. Small differences in setpoint can materially affect voltage constraint results in both directions, so this value should reflect realistic operating practice for your network. Typical values range from 0.94 to 1.02 p.u., with 0.98-0.99 representing standard utility practice."}),"\n",(0,a.jsxs)(t.h3,{id:"voltage-deadband-closed_loop_v_band",children:["Voltage Deadband (",(0,a.jsx)(t.code,{children:"closed_loop_v_band"}),")"]}),"\n",(0,a.jsx)(t.p,{children:"The deadband defines a tolerance band (in %) around the setpoint within which the regulator remains idle. Without a deadband, the regulator would continuously hunt for the exact setpoint in response to minor fluctuations - a condition known as tap hunting, which causes equipment wear and customer voltage flicker. For example, a setpoint of 0.985 with a deadband of 2% means the regulator won't act unless voltage falls outside the range 0.965-1.005 p.u."}),"\n",(0,a.jsx)(t.p,{children:"A tighter deadband preserves more overvoltage headroom but increases tap operations. A wider deadband reduces tap operations but allows more voltage drift, consuming voltage margin in both directions. The deadband also interacts with the time delay: a very tight deadband will cause more tap operations unless paired with a suitably long delay to avoid hunting. Typical values are 1-5%."}),"\n",(0,a.jsxs)(t.h3,{id:"time-delay-closed_loop_time_delay",children:["Time Delay (",(0,a.jsx)(t.code,{children:"closed_loop_time_delay"}),")"]}),"\n",(0,a.jsx)(t.p,{children:"The time delay (in seconds) controls how long voltage must remain outside the deadband before a tap change is triggered."}),"\n",(0,a.jsx)(t.p,{children:"Description:"}),"\n",(0,a.jsx)(t.p,{children:"The time delay (in seconds) controls how long a voltage violation must persist at a regulator's sensing point before that regulator initiates a tap change command."}),"\n",(0,a.jsx)(t.p,{children:"In single-regulator systems, this parameter has minimal effect due to the 30-minute time resolution of the simulation (the violation window between time steps far exceeds the delay threshold)."}),"\n",(0,a.jsx)(t.p,{children:"In multi-regulator systems, this parameter determines regulator priority (regulators with SHORTER delays act FIRST, regulators with LONGER delays act LATER). This allows coordinated control where upstream regulators (shorter delay) attempt voltage correction before downstream regulators (longer delay) respond, reducing unnecessary tap operations and 'hunting' behaviour."}),"\n",(0,a.jsx)(t.p,{children:"The specific values used should reflect the network topology and desired control hierarchy based on exisitng downstream regulators."}),"\n",(0,a.jsxs)(t.h3,{id:"voltage-limit-closed_loop_v_limit",children:["Voltage Limit (",(0,a.jsx)(t.code,{children:"closed_loop_v_limit"}),")"]}),"\n",(0,a.jsx)(t.p,{children:"The voltage limit is a hard ceiling in per-unit, set to protect equipment and comply with regulatory requirements - in most Australian frameworks, voltage must stay within +/-10% of nominal (0.90-1.10 p.u.)."}),"\n",(0,a.jsx)(t.p,{children:"In high-DER scenarios, the voltage limit is frequently the binding constraint. Once approached, additional generation cannot be accommodated without causing a violation - this is what ultimately caps hosting capacity. The voltage limit is often more influential than any other parameter: reducing it from 1.10 to 1.05 p.u. can significantly reduce predicted hosting capacity on solar-heavy feeders. Typical values are 1.05-1.10 p.u."}),"\n",(0,a.jsx)(t.h3,{id:"deployment-flags",children:"Deployment Flags"}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.code,{children:"closed_loop_v_reg_enabled"})," controls whether CLVC regulators are deployed at zone substations at all. When set to ",(0,a.jsx)(t.code,{children:"false"}),", existing regulators are modelled as-is using their existing Line Drop Compensation (LDC) settings from the network model. If a zone substation has no existing regulator and ",(0,a.jsx)(t.code,{children:"enabled"})," is ",(0,a.jsx)(t.code,{children:"false"}),", that substation will have no active voltage control in the model at all."]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.code,{children:"closed_loop_v_reg_replace_all"})," controls whether all existing regulators are replaced with the configured CLVC settings, or whether CLVC is only added where no regulator exists. Setting both to ",(0,a.jsx)(t.code,{children:"true"})," gives consistent, reproducible behaviour across the network and is generally recommended for planning studies. Setting ",(0,a.jsx)(t.code,{children:"replace_all"})," to ",(0,a.jsx)(t.code,{children:"false"})," is appropriate when modelling heterogeneous configurations, for example where some substations have CLVC and others use LDC or have fixed taps."]}),"\n",(0,a.jsx)(t.h2,{id:"scope-and-limitations",children:"Scope and Limitations"}),"\n",(0,a.jsxs)(t.p,{children:["CLVC is a network-wide modelling assumption. When ",(0,a.jsx)(t.code,{children:"closed_loop_v_reg_replace_all"})," is set to ",(0,a.jsx)(t.code,{children:"true"}),", the same control scheme and parameters apply uniformly to every zone substation in the work package. This makes it straightforward to configure, but means it cannot reflect the reality that different substations may have different regulator settings or that only some feeders have active voltage control."]}),"\n",(0,a.jsxs)(t.p,{children:["Because CLVC affects every feeder, changes to the configuration affect results across the entire network - there is no way to apply different CLVC settings to individual feeders or substations within a single work package. If your network has significantly different regulator configurations at different zone substations, consider running separate work packages, or using ",(0,a.jsx)(t.code,{children:"replace_all = false"})," to preserve the existing diversity in the network model."]}),"\n",(0,a.jsx)(t.h2,{id:"comparison-with-other-voltage-control-options",children:"Comparison with Other Voltage Control Options"}),"\n",(0,a.jsx)(t.p,{children:"The HCM also includes several intervention types that address voltage through different mechanisms. Understanding the distinction helps when choosing the right tool for a given analysis."}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"DVMS (Dynamic Voltage Management System)"})," is the most direct analogue to CLVC - both control zone substation taps. The key difference is that DVMS is a targeted intervention applied after a base work package, using a more sophisticated dual-loop control algorithm that responds to actual customer voltage distributions rather than a single sensing-point measurement. DVMS is considerably more computationally intensive as it re-solves the network at each time step. CLVC, by contrast, is the baseline voltage control assumption applied uniformly across the network and is far less expensive to compute."]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"DISTRIBUTION_TAP_OPTIMIZATION"})," adjusts distribution transformer taps, not zone substation taps. It makes static, once-per-year tap changes based on historical voltage patterns from the base work package - there is no real-time feedback. It is best suited to addressing persistent, predictable voltage bias on LV circuits where a fixed tap adjustment would improve annual compliance."]}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"DISTRIBUTION_TX_OLTC"})," retrofits distribution transformers with on-load tap changers, enabling dynamic voltage regulation at the LV level. This operates downstream of where CLVC acts and complements rather than replaces zone substation regulation."]}),"\n",(0,a.jsx)(t.h2,{id:"choosing-settings",children:"Choosing Settings"}),"\n",(0,a.jsx)(t.p,{children:'The voltage limit and setpoint are typically the most influential parameters. Note that because the HCM captures both overvoltage and undervoltage constraints, the "best" settings depend on the nature of your network - a low setpoint helps generation-heavy networks but may worsen results on load-heavy feeders with long runs.'}),"\n",(0,a.jsx)(t.p,{children:"For a generation-heavy network, use a lower setpoint and tighter deadband to maximise overvoltage headroom. This gives the best conditions for DER but may understate undervoltage risk under high load."}),"\n",(0,a.jsx)(t.p,{children:"For a realistic or baseline analysis, use settings that reflect your network's actual zone substation operating practice, or the defaults. This is the most appropriate starting point for general network constraint analysis."}),"\n",(0,a.jsx)(t.p,{children:"For a load-heavy or long-feeder network, a higher setpoint may reduce undervoltage constraints under high demand, at the cost of less overvoltage headroom."}),"\n",(0,a.jsx)(t.p,{children:"Time delay has no practical effect at 30-minute resolution unless set above 1800 seconds."}),"\n",(0,a.jsx)(t.h3,{id:"example-configurations",children:"Example Configurations"}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.strong,{children:"High DER penetration - aggressive regulation"})}),"\n",(0,a.jsx)(t.pre,{children:(0,a.jsx)(t.code,{children:"closed_loop_v_reg_set_point = 0.96\nclosed_loop_v_band = 1.5\nclosed_loop_time_delay = 100\nclosed_loop_v_limit = 1.05\n"})}),"\n",(0,a.jsx)(t.p,{children:"Low setpoint and limit with a tight, responsive deadband. Maximises overvoltage headroom for generation-heavy networks. May worsen undervoltage outcomes on load-heavy feeders."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.strong,{children:"Standard distribution feeder - defaults"})}),"\n",(0,a.jsx)(t.pre,{children:(0,a.jsx)(t.code,{children:"closed_loop_v_reg_set_point = 0.985\nclosed_loop_v_band = 2.0\nclosed_loop_time_delay = 100\nclosed_loop_v_limit = 1.1\n"})}),"\n",(0,a.jsx)(t.p,{children:"Reflects ANSI voltage standards and typical utility practice. A reasonable baseline for most analyses."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.strong,{children:"Conservative planning estimate"})}),"\n",(0,a.jsx)(t.pre,{children:(0,a.jsx)(t.code,{children:"closed_loop_v_reg_set_point = 0.99\nclosed_loop_v_band = 2.5\nclosed_loop_time_delay = 100\nclosed_loop_v_limit = 1.1\n"})}),"\n",(0,a.jsx)(t.p,{children:"Higher setpoint and wider deadband. Reduces overvoltage headroom but may improve undervoltage outcomes on load-heavy or long-feeder networks."})]})}function h(e={}){let{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(c,{...e})}):c(e)}},8453:function(e,t,o){o.d(t,{R:()=>i,x:()=>r});var n=o(6540);let a={},s=n.createContext(a);function i(e){let t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:i(e.components),n.createElement(s.Provider,{value:t},e.children)}}}]);